import { useState, useEffect } from 'react';
import API from '../Api/Axios';
import toast from 'react-hot-toast';
import './Transaction.css';

const Transaction = () => {
    const [search, setSearch] = useState('');
  const [invoices, setInvoices] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);
  const [filterType, setFilterType] = useState('all'); // all | date | month
  const [filterDate, setFilterDate] = useState('');
  const [filterMonth, setFilterMonth] = useState('');

 useEffect(() => {
  let result = [...invoices];

  if (filterType === 'date' && filterDate) {
    result = result.filter((inv) => {
      const invDate = new Date(inv.createdAt).toISOString().slice(0, 10);
      return invDate === filterDate;
    });
  }

  if (filterType === 'month' && filterMonth) {
    const [year, month] = filterMonth.split('-');
    result = result.filter((inv) => {
      const d = new Date(inv.createdAt);
      return (
        d.getFullYear() === parseInt(year) &&
        d.getMonth() + 1 === parseInt(month)
      );
    });
  }

  if (search.trim()) {
    result = result.filter((inv) =>
      inv.customerName.toLowerCase().includes(search.toLowerCase())
    );
  }

  setFiltered(result);
}, [filterType, filterDate, filterMonth, search, invoices]);

  // Apply filters
  useEffect(() => {
    let result = [...invoices];

    if (filterType === 'date' && filterDate) {
      result = result.filter((inv) => {
        const invDate = new Date(inv.createdAt).toISOString().slice(0, 10);
        return invDate === filterDate;
      });
    }

    if (filterType === 'month' && filterMonth) {
      const [year, month] = filterMonth.split('-');
      result = result.filter((inv) => {
        const d = new Date(inv.createdAt);
        return (
          d.getFullYear() === parseInt(year) &&
          d.getMonth() + 1 === parseInt(month)
        );
      });
    }

    setFiltered(result);
  }, [filterType, filterDate, filterMonth, invoices]);

  const formatDate = (dateStr) =>
    new Date(dateStr).toLocaleString('en-PK', {
      year: 'numeric', month: 'short', day: 'numeric',
      hour: '2-digit', minute: '2-digit', hour12: true,
    });

  const totalAmount = filtered.reduce((sum, inv) => sum + inv.totalAmount, 0);

  return (
    <div className="tr-page">

      {/* Top Bar */}
      <div className="tr-topbar">
        <div>
          <h1>Transactions</h1>
          <p>{filtered.length} transaction{filtered.length !== 1 ? 's' : ''} found</p>
        </div>
        <div className="tr-summary-badge">
          Total: Rs. {totalAmount.toFixed(2)}
        </div>
      </div>

      {/* Filters */}
      <div className="tr-filters">
        <div className="tr-filter-tabs">
          {['all', 'date', 'month'].map((type) => (
            <button
              key={type}
              className={`tr-tab ${filterType === type ? 'active' : ''}`}
              onClick={() => setFilterType(type)}
            >
              {type === 'all' ? 'All' : type === 'date' ? 'By Date' : 'By Month'}
            </button>
          ))}
        </div>

        {filterType === 'date' && (
          <input
            type="date"
            className="tr-filter-input"
            value={filterDate}
            onChange={(e) => setFilterDate(e.target.value)}
          />
          
        )}

        {filterType === 'month' && (
          <input
            type="month"
            className="tr-filter-input"
            value={filterMonth}
            onChange={(e) => setFilterMonth(e.target.value)}
          />
        )}
          <input
    type="text"
    className="tr-filter-input tr-search"
    placeholder="Search by customer name..."
    value={search}
    onChange={(e) => setSearch(e.target.value)}
  />
      </div>

      {/* List */}
      {loading ? (
        <div className="tr-empty">Loading...</div>
      ) : filtered.length === 0 ? (
        <div className="tr-empty">
          <span>🧾</span>
          <p>No transactions found</p>
        </div>
      ) : (
        <div className="tr-list">
          {filtered.map((inv) => (
            <div key={inv._id} className="tr-card" onClick={() => setSelected(inv)}>
              <div className="tr-card-left">
                <div className="tr-icon">🧾</div>
                <div className="tr-info">
                  <span className="tr-customer">{inv.customerName}</span>
                  <span className="tr-inv-no">{inv.invoiceNumber}</span>
                  <span className="tr-date">{formatDate(inv.createdAt)}</span>
                </div>
              </div>
              <div className="tr-card-right">
                <span className="tr-amount">Rs. {inv.totalAmount.toFixed(2)}</span>
                {inv.tax > 0 && (
                  <span className="tr-tax-badge">GST {inv.tax}%</span>
                )}
                <span className="tr-items-count">{inv.items.length} item{inv.items.length !== 1 ? 's' : ''}</span>
                <button className="tr-view-btn">View →</button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Detail Modal */}
      {selected && (
        <div className="modal-overlay" onClick={() => setSelected(null)}>
          <div className="tr-modal" onClick={(e) => e.stopPropagation()}>

            {/* Modal Header */}
            <div className="tr-modal-header">
              <div>
                <h2>{selected.customerName}</h2>
                <span className="tr-modal-inv">{selected.invoiceNumber}</span>
              </div>
              <button className="modal-close" onClick={() => setSelected(null)}>✕</button>
            </div>

            {/* Modal Body */}
            <div className="tr-modal-body">

              {/* Meta */}
              <div className="tr-meta-grid">
                <div className="tr-meta-item">
                  <span className="tr-meta-label">Date & Time</span>
                  <span className="tr-meta-value">{formatDate(selected.createdAt)}</span>
                </div>
                <div className="tr-meta-item">
                  <span className="tr-meta-label">Invoice No.</span>
                  <span className="tr-meta-value">{selected.invoiceNumber}</span>
                </div>
                <div className="tr-meta-item">
                  <span className="tr-meta-label">Customer</span>
                  <span className="tr-meta-value">{selected.customerName}</span>
                </div>
                <div className="tr-meta-item">
                  <span className="tr-meta-label">Tax Applied</span>
                  <span className="tr-meta-value">{selected.tax > 0 ? `${selected.tax}%` : 'None'}</span>
                </div>
              </div>

              {/* Items */}
              <div className="tr-modal-section-title">Items Ordered</div>
              <table className="tr-detail-table">
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Item</th>
                    <th>Price</th>
                    <th>Qty</th>
                    <th>Total</th>
                  </tr>
                </thead>
                <tbody>
                  {selected.items.map((item, i) => (
                    <tr key={i}>
                      <td>{i + 1}</td>
                      <td>{item.name}</td>
                      <td>Rs. {item.price}</td>
                      <td>{item.quantity}</td>
                      <td>Rs. {item.subtotal}</td>
                    </tr>
                  ))}
                </tbody>
              </table>

              {/* Totals */}
              <div className="tr-totals">
                <div className="tr-total-row">
                  <span>Subtotal</span>
                  <span>Rs. {selected.subtotal.toFixed(2)}</span>
                </div>
                {selected.tax > 0 && (
                  <div className="tr-total-row">
                    <span>GST ({selected.tax}%)</span>
                    <span>Rs. {(selected.totalAmount - selected.subtotal).toFixed(2)}</span>
                  </div>
                )}
                <div className="tr-total-row grand">
                  <span>Grand Total</span>
                  <span>Rs. {selected.totalAmount.toFixed(2)}</span>
                </div>
              </div>

            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default Transaction;
